import re

def scrub_logs(log_string):
    # Use a try-except block to catch any unexpected regex or type errors.
    try:
        if not isinstance(log_string, str):
            return log_string # Or "" if you prefer strictness, but returning original is safer per requirement.

        # More flexible pattern: looks for specific labels followed by non-whitespace characters that look like keys.
        pattern = r"(api_key=|key:|token=|secret:)\s*([a-zA-Z0-9\-_]+)"
        return re.sub(pattern, r"\1[REDACTED]", log_string)
    except Exception:
        # If anything crashes (bad input, regex error), return the original log string unredacted.
        return log_string

